import React, { useState, useEffect } from 'react';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const getRoleBadgeClass = (role) => {
    const map = {
        'SuperAdmin': 'badge-superadmin', 'User': 'badge-user',
        'Networking Staff': 'badge-network', 'Plumber': 'badge-plumber',
        'Electrician': 'badge-electrician', 'Software Developer': 'badge-developer',
    };
    return map[role] || 'badge-primary';
};

const UserMaster = () => {
    const [users, setUsers] = useState([]);
    const [formData, setFormData] = useState({
        userName: '', email: '', password: '', phoneNumber: '', role: 'User', department: '', programme: ''
    });
    const [loading, setLoading] = useState(false);
    const [programmes, setProgrammes] = useState([]);
    const [message, setMessage] = useState('');
    const [isEditing, setIsEditing] = useState(false);
    const [editId, setEditId] = useState(null);

    const roleOptions = ['SuperAdmin', 'User', 'Networking Staff', 'Plumber', 'Electrician', 'Software Developer', 'Cleaner', 'Carpenter'];

    useEffect(() => { fetchUsers(); fetchProgrammes(); }, []);

    const fetchUsers = async () => {
        try { const { data } = await API.get('/master/users'); setUsers(data); }
        catch (err) { console.error('Error fetching users', err); }
    };
    
    const fetchProgrammes = async () => {
        try {
            const { data } = await API.get('/master/programme');
            setProgrammes(data);
        } catch (err) { console.error('Error fetching programmes', err); }
    };

    const handleProgrammeChange = (e) => {
        const progId = e.target.value;
        const selectedProg = programmes.find(p => p._id === progId);
        setFormData({ 
            ...formData, 
            programme: progId, 
            department: selectedProg?.department?._id || '' 
        });
    };

    const handleEdit = (user) => {
        setIsEditing(true);
        setEditId(user._id);
        setFormData({
            userName: user.userName,
            email: user.email,
            password: '', // Keep empty unless changing
            phoneNumber: user.phoneNumber || '',
            role: user.role,
            department: user.department?._id || user.department || '',
            programme: user.programme?._id || user.programme || ''
        });
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    const handleDelete = async (id) => {
        if (!window.confirm('Are you sure you want to delete this user?')) return;
        try {
            await API.delete(`/master/users/${id}`);
            fetchUsers();
            setMessage({ type: 'success', text: '✓ User deleted successfully!' });
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error deleting user' });
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            if (isEditing) {
                const updateData = { ...formData };
                if (!updateData.password) delete updateData.password; // Don't update if empty
                await API.put(`/master/users/${editId}`, updateData);
                setMessage({ type: 'success', text: '✓ User updated successfully!' });
            } else {
                await API.post('/master/users', formData);
                setMessage({ type: 'success', text: '✓ User created successfully!' });
            }
            setFormData({ userName: '', email: '', password: '', phoneNumber: '', role: 'User', department: '', programme: '' });
            setIsEditing(false);
            setEditId(null);
            fetchUsers();
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: isEditing ? '✗ Error updating user' : '✗ Error creating user' });
            setTimeout(() => setMessage(''), 3000);
        } finally { setLoading(false); }
    };

    const resetForm = () => {
        setFormData({ userName: '', email: '', password: '', phoneNumber: '', role: 'User', department: '', programme: '' });
        setIsEditing(false);
        setEditId(null);
    };

    return (
        <div className="page-wrapper">
            <Navigation />
            <div className="content-area">
                <div className="header-section">
                    <h1 className="main-title">👤 User Management</h1>
                    <p className="subtitle">Create and manage user accounts</p>
                </div>

                {message && (
                    <div className={`alert ${message.type === 'success' ? 'alert-success' : 'alert-error'}`}>
                        {message.text}
                    </div>
                )}

                <div className="master-grid">
                    <div className="glass-card">
                        <form onSubmit={handleSubmit} className="form-body">
                            <h3 className="form-title">{isEditing ? '✏️ Edit User' : '👤 Create New User'}</h3>
                            <div className="form-group">
                                <label className="form-label">Username</label>
                                <input type="text" required placeholder="Enter username..."
                                    value={formData.userName}
                                    onChange={e => setFormData({ ...formData, userName: e.target.value })}
                                    className="form-input" />
                            </div>
                            <div className="form-group">
                                <label className="form-label">Email</label>
                                <input type="email" required placeholder="Enter email..."
                                    value={formData.email}
                                    onChange={e => setFormData({ ...formData, email: e.target.value })}
                                    className="form-input" />
                            </div>
                            <div className="form-group">
                                <label className="form-label">Password {isEditing && '(Leave blank to keep same)'}</label>
                                <input type="password" required={!isEditing} placeholder={isEditing ? "Enter new password..." : "Enter password..."}
                                    value={formData.password}
                                    onChange={e => setFormData({ ...formData, password: e.target.value })}
                                    className="form-input" />
                            </div>
                            <div className="form-group">
                                <label className="form-label">Phone Number</label>
                                <input type="tel" required placeholder="10-digit phone..."
                                    value={formData.phoneNumber}
                                    onChange={e => setFormData({ ...formData, phoneNumber: e.target.value })}
                                    className="form-input" />
                            </div>
                            <div className="form-group">
                                <label className="form-label">Role</label>
                                <select required value={formData.role}
                                    onChange={e => setFormData({ ...formData, role: e.target.value })}
                                    className="form-select">
                                    {roleOptions.map(role => <option key={role} value={role}>{role}</option>)}
                                </select>
                            </div>
                            <div className="form-group">
                                <label className="form-label">Programme / Course</label>
                                <select required value={formData.programme} onChange={handleProgrammeChange} className="form-select">
                                    <option value="">Select Programme</option>
                                    {programmes.map(p => (
                                        <option key={p._id} value={p._id}>
                                            {p.programmeName} ({p.programmeShortName})
                                        </option>
                                    ))}
                                </select>
                            </div>
                            <div className="form-actions">
                                <button type="submit" disabled={loading} className="btn btn-primary" style={{ flex: 1 }}>
                                    {loading ? 'Processing...' : (isEditing ? 'Update User' : '+ Create User')}
                                </button>
                                {isEditing && (
                                    <button type="button" onClick={resetForm} className="btn btn-secondary">
                                        Cancel
                                    </button>
                                )}
                            </div>
                        </form>
                    </div>

                    <div className="table-card">
                        <h3 className="table-title">📋 Users List</h3>
                        <div className="table-scroll">
                            <table className="data-table">
                                <thead>
                                    <tr>
                                        <th>Username</th>
                                        <th>Role</th>
                                        <th>Programme</th>
                                        <th style={{ textAlign: 'center' }}>Actions</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {users.length > 0 ? users.map(user => (
                                        <tr key={user._id}>
                                            <td>
                                                <div style={{ fontWeight: '500' }}>{user.userName}</div>
                                                <div style={{ fontSize: '0.8rem', color: '#666' }}>{user.email}</div>
                                            </td>
                                            <td><span className={`badge ${getRoleBadgeClass(user.role)}`}>{user.role}</span></td>
                                            <td>{user.programme?.programmeShortName || '-'}</td>
                                            <td className="table-actions">
                                                <button onClick={() => handleEdit(user)} className="btn-icon-only" title="Edit">✏️</button>
                                                <button onClick={() => handleDelete(user._id)} className="btn-icon-only text-error" title="Delete">🗑️</button>
                                            </td>
                                        </tr>
                                    )) : (
                                        <tr><td colSpan="4" className="table-empty">No users found</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default UserMaster;
